def find_all(text, pattern):
    """KMP algorithm with optimized failure function."""
    n = len(text)
    m = len(pattern)
    if m == 0:
        return []
    if m > n:
        return []
    # Compute partial match table (failure function)
    lps = [0] * m
    length = 0
    i = 1
    while i < m:
        if pattern[i] == pattern[length]:
            length += 1
            lps[i] = length
            i += 1
        else:
            if length != 0:
                length = lps[length - 1]
            else:
                lps[i] = 0
                i += 1
    # Perform search
    result = []
    i = 0
    j = 0
    while i < n:
        if pattern[j] == text[i]:
            i += 1
            j += 1
        if j == m:
            result.append(i - j)
            j = lps[j - 1]
        elif i < n and pattern[j] != text[i]:
            if j != 0:
                j = lps[j - 1]
            else:
                i += 1
    return result

def find_all(text, pattern):
    """Boyer-Moore with bad character rule only."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    # Bad character table: last occurrence of each char in pattern
    bad_char = {}
    for i in range(m):
        bad_char[pattern[i]] = i
    result = []
    s = 0  # shift of pattern over text
    while s <= n - m:
        j = m - 1
        while j >= 0 and pattern[j] == text[s + j]:
            j -= 1
        if j < 0:
            result.append(s)
            # Shift pattern so next char in text aligns with last occurrence in pattern
            if s + m < n:
                s += m - bad_char.get(text[s + m], -1)
            else:
                s += 1
        else:
            bc_shift = j - bad_char.get(text[s + j], -1)
            s += max(1, bc_shift)
    return result

def find_all(text, pattern):
    """Z-algorithm based matcher."""
    m = len(pattern)
    n = len(text)
    if m == 0 or m > n:
        return []
    # Build Z-array for pattern$text
    s = pattern + '\x00' + text
    slen = len(s)
    z = [0] * slen
    z[0] = slen
    rt = 0
    lt = 0
    for i in range(1, slen):
        if i > rt:
            lt = rt = i
            while rt < slen and s[rt - lt] == s[rt]:
                rt += 1
            z[i] = rt - lt
            rt -= 1
        else:
            k = i - lt
            if z[k] < rt - i + 1:
                z[i] = z[k]
            else:
                lt = i
                while rt < slen and s[rt - lt] == s[rt]:
                    rt += 1
                z[i] = rt - lt
                rt -= 1
    result = []
    offset = m + 1
    for i in range(offset, slen):
        if z[i] == m:
            result.append(i - offset)
    return result

def find_all(text, pattern):
    """Sunday algorithm (variant of Boyer-Moore)."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    # Precompute shift table: for each character, how far to shift
    # when mismatch occurs, based on next character after window
    shift = {}
    for i in range(m):
        shift[pattern[i]] = m - i
    default_shift = m + 1
    result = []
    i = 0
    while i <= n - m:
        j = 0
        while j < m and text[i + j] == pattern[j]:
            j += 1
        if j == m:
            result.append(i)
        # Shift based on character just after the current window
        next_pos = i + m
        if next_pos < n:
            i += shift.get(text[next_pos], default_shift)
        else:
            i += 1
    return result
